// src/pages/Paiements.jsx
import React, { useState, useEffect } from 'react';
import { getPaiements, addPaiement } from '../services/api';

function Paiements() {
  const [paiements, setPaiements] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const [formData, setFormData] = useState({
    montant: '',
    date_paiement: new Date().toISOString().split('T')[0],
    mode_paiement: 'Espèces',
    statut: 'Payé',
    id_abonnement: '',
  });

  const fetchPaiements = async () => {
    try {
      const res = await getPaiements();
      setPaiements(res.data || []);
      setLoading(false);
      setError(null);
    } catch (err) {
      console.error('Erreur fetch paiements:', err);
      setError(err.response?.data?.error || 'Impossible de charger les paiements');
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchPaiements();
  }, []);

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value,
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const res = await addPaiement(formData);
      alert(res.data?.message || 'Paiement enregistré avec succès !');
      setFormData({
        montant: '',
        date_paiement: new Date().toISOString().split('T')[0],
        mode_paiement: 'Espèces',
        statut: 'Payé',
        id_abonnement: '',
      });
      fetchPaiements();
    } catch (err) {
      alert(err.response?.data?.error || 'Erreur lors de l’enregistrement');
      console.error(err);
    }
  };

  return (
    <div className="container mt-5">
      <h2 className="mb-4 text-center">Gestion des Paiements</h2>

      {/* Formulaire */}
      <div className="card shadow mb-5">
        <div className="card-header bg-success text-white">
          <h5 className="mb-0">Enregistrer un paiement</h5>
        </div>
        <div className="card-body">
          <form onSubmit={handleSubmit}>
            <div className="row g-3">
              <div className="col-md-3">
                <label className="form-label">Montant (DH)</label>
                <input
                  type="number"
                  name="montant"
                  step="0.01"
                  min="0"
                  className="form-control"
                  value={formData.montant}
                  onChange={handleChange}
                  required
                />
              </div>

              <div className="col-md-3">
                <label className="form-label">Date</label>
                <input
                  type="date"
                  name="date_paiement"
                  className="form-control"
                  value={formData.date_paiement}
                  onChange={handleChange}
                  required
                />
              </div>

              <div className="col-md-3">
                <label className="form-label">Mode de paiement</label>
                <select
                  name="mode_paiement"
                  className="form-select"
                  value={formData.mode_paiement}
                  onChange={handleChange}
                  required
                >
                  <option value="Espèces">Espèces</option>
                  <option value="Carte">Carte bancaire</option>
                  <option value="Virement">Virement</option>
                  <option value="Mobile">Mobile Money</option>
                </select>
              </div>

              <div className="col-md-3">
                <label className="form-label">Statut</label>
                <select
                  name="statut"
                  className="form-select"
                  value={formData.statut}
                  onChange={handleChange}
                  required
                >
                  <option value="Payé">Payé</option>
                  <option value="En attente">En attente</option>
                  <option value="Annulé">Annulé</option>
                </select>
              </div>

              <div className="col-12">
                <label className="form-label">ID Abonnement</label>
                <input
                  type="number"
                  name="id_abonnement"
                  className="form-control"
                  placeholder="Entrez l'ID de l'abonnement"
                  value={formData.id_abonnement}
                  onChange={handleChange}
                  required
                />
              </div>
            </div>

            <div className="mt-4 text-end">
              <button type="submit" className="btn btn-success">
                Enregistrer
              </button>
            </div>
          </form>
        </div>
      </div>

      {/* Liste */}
      <h4 className="mb-3">Historique des paiements</h4>

      {loading ? (
        <p className="text-center">Chargement...</p>
      ) : error ? (
        <div className="alert alert-danger">{error}</div>
      ) : paiements.length === 0 ? (
        <div className="alert alert-info">Aucun paiement enregistré</div>
      ) : (
        <div className="table-responsive">
          <table className="table table-striped table-hover">
            <thead className="table-dark">
              <tr>
                <th>ID</th>
                <th>Montant</th>
                <th>Date</th>
                <th>Mode</th>
                <th>Statut</th>
                <th>Abonnement</th>
                <th>Membre</th>
              </tr>
            </thead>
            <tbody>
              {paiements.map((p) => (
                <tr key={p.id_paiement}>
                  <td>{p.id_paiement}</td>
                  <td>{p.montant} DH</td>
                  <td>{p.date_paiement}</td>
                  <td>{p.mode_paiement}</td>
                  <td className={
                    p.statut === 'Payé' ? 'text-success' :
                    p.statut === 'En attente' ? 'text-warning' :
                    'text-danger'
                  }>
                    {p.statut}
                  </td>
                  <td>{p.type_abonnement || '-'}</td>
                  <td>{p.nom_membre || '-'}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

export default Paiements;
